// Implement the rescue workflow. Connect via src/db.mjs, read raw account
// facts, derive the answer per ../RULES.md, and PERSIST workflow_state,
// owner_tasks, customer_messages, audit_events back to the live database.
//
// export an async function run() that performs the full read->derive->persist.
import { withDb, cfg } from "./db.mjs";

const QUALIFYING_TIERS = ["strategic", "enterprise"];
const HIGH_SEVERITIES = ["high", "critical"];
const INVOICE_HIGH_CENTS = 2_500_000;
const USAGE_DROP_FRACTION = 0.30;

const SIGNAL_ORDER = ["regulatory", "invoice", "shipment", "support", "usage"];
const SIGNAL_NAME = {
  regulatory: "Regulatory hold",
  invoice: "Overdue invoice",
  shipment: "Delayed shipment",
  support: "Escalated support",
  usage: "Usage decline"
};

const OWNER_FOR_CATEGORY = {
  regulatory: "Legal",
  invoice: "Finance",
  shipment: "Customer Success",
  usage: "Customer Success",
  support: "Support"
};
const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];

function evaluateRisks(world, nowMs) {
  const fired = {};

  const overdueInvoice = (world.invoices || []).find(
    (inv) => inv.status !== "paid" && Date.parse(inv.dueDate) < nowMs && inv.amountCents >= INVOICE_HIGH_CENTS
  );
  if (overdueInvoice) fired.invoice = true;

  const lateShipment = (world.shipments || []).find(
    (sh) => !sh.deliveredDate && Date.parse(sh.slaDate) < nowMs
  );
  if (lateShipment) fired.shipment = true;

  const openReg = (world.regulatoryFlags || []).find((flag) => flag.status === "open");
  if (openReg) fired.regulatory = true;

  const escalatedSupport = (world.supportCases || []).find(
    (c) => c.status === "open" && HIGH_SEVERITIES.includes(c.severity)
  );
  if (escalatedSupport) fired.support = true;

  const usage = world.usage || {};
  if (
    typeof usage.priorPeriodUnits === "number" &&
    typeof usage.currentPeriodUnits === "number" &&
    usage.priorPeriodUnits > 0 &&
    usage.currentPeriodUnits <= usage.priorPeriodUnits * (1 - USAGE_DROP_FRACTION)
  ) {
    fired.usage = true;
  }

  return fired;
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  const nowMs = Date.parse(now);

  await withDb(async (db) => {
    // Read account doc
    const row = (await db.query("SELECT doc FROM accounts LIMIT 1")).rows[0];
    const doc = row.doc;

    const world = {
      account: { accountId: doc._id, name: doc.name, tier: doc.tier, region: doc.region },
      invoices: doc.invoices,
      shipments: doc.shipments,
      regulatoryFlags: doc.regulatoryFlags,
      supportCases: doc.supportCases,
      usage: doc.usage
    };

    const accountId = doc._id;
    const requestId = doc.request?.requestId || `req-${accountId}`;
    const accountName = doc.name;

    // Evaluate risks
    const fired = evaluateRisks(world, nowMs);

    // Ordered signals
    const signals = SIGNAL_ORDER.filter((cat) => fired[cat]).map((cat) => ({
      category: cat,
      name: SIGNAL_NAME[cat]
    }));

    // Check qualification
    const tierOk = QUALIFYING_TIERS.includes(String(world.account.tier || "").toLowerCase());
    const qualifiesForEscalation = tierOk && signals.length >= 1;

    // Derive owners
    const ownerSet = new Set();
    for (const cat of Object.keys(fired)) ownerSet.add(OWNER_FOR_CATEGORY[cat]);
    const owners = qualifiesForEscalation ? OWNER_ORDER.filter((o) => ownerSet.has(o)) : [];

    // Derive status, next_step, risk_summary
    const status = qualifiesForEscalation
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    const nextStep = qualifiesForEscalation
      ? `${owners[0]} recovery review by 16:00`
      : "Continue standard monitoring.";

